#!/usr/bin/env bash
# ============================================================
#  3x-UI Telegram Bot — One-Click VPS Installer (Multi-Bot)
#  Supports multiple bots on same VPS via unique bot names.
#  Run:  bash setup-3xui-bot.sh
# ============================================================
set -e

RED='\033[0;31m'; GREEN='\033[0;32m'; YELLOW='\033[1;33m'; CYAN='\033[0;36m'; NC='\033[0m'
log()  { echo -e "${GREEN}[+]${NC} $1"; }
err()  { echo -e "${RED}[✗]${NC} $1"; }
info() { echo -e "${CYAN}[i]${NC} $1"; }

echo ""
echo -e "${CYAN}╔═════════════════════════════════════════════════════╗${NC}"
echo -e "${CYAN}║   3x-UI Telegram Bot — VPS Installer by Arielvpn    ║${NC}"
echo -e "${CYAN}╚═════════════════════════════════════════════════════╝${NC}"
echo ""

# ── Step 1: Bot Name ────────────────────────────────────────
echo -e "${YELLOW}Step 1: Bot Identity${NC}"
while [ -z "$BOT_NAME" ]; do
    read -p "  🏷  Bot name (e.g. panel1, nyc-vps): " BOT_NAME
    [ -z "$BOT_NAME" ] && echo -e "     ${RED}⚠ Required — for multi-bot support${NC}"
done
BOT_NAME=$(echo "$BOT_NAME" | tr '[:upper:]' '[:lower:]' | tr ' ' '-' | sed 's/[^a-z0-9-]//g')
BOT_DIR="/opt/${BOT_NAME}"
SVC_NAME="${BOT_NAME}"
echo -e "  ${GREEN}→ Directory: $BOT_DIR${NC}"
echo -e "  ${GREEN}→ Service:   $SVC_NAME${NC}"
echo ""

# ── Step 2: Config ──────────────────────────────────────────
echo -e "${YELLOW}Step 2: Configuration${NC}"
echo ""
while [ -z "$BOT_OWNER" ]; do
    read -p "  👑 Your Telegram User ID (bot owner/admin): " BOT_OWNER
    [ -z "$BOT_OWNER" ] && echo -e "     ${RED}⚠ Required — owner who can manage users${NC}"
done
read -p "  👥 Additional Allowed User IDs (comma-separated, or leave empty): " TG_EXTRA_USERS

# Build combined allowed list (owner always included)
if [ -z "$TG_EXTRA_USERS" ]; then
    TG_ALLOWED_USERS="$BOT_OWNER"
else
    TG_ALLOWED_USERS="$BOT_OWNER,$TG_EXTRA_USERS"
fi
while [ -z "$TG_BOT_TOKEN" ]; do
    read -p "  📱 Telegram Bot Token (@BotFather): " TG_BOT_TOKEN
    [ -z "$TG_BOT_TOKEN" ] && echo -e "     ${RED}⚠ Required${NC}"
done
while [ -z "$XUI_API_TOKEN" ]; do
    read -p "  🔑 3x-UI API Token: " XUI_API_TOKEN
    [ -z "$XUI_API_TOKEN" ] && echo -e "     ${RED}⚠ Required${NC}"
done
while [ -z "$XUI_PANEL_URL" ]; do
    read -p "  🌐 3x-UI Panel URL (e.g. https://IP:PORT/path): " XUI_PANEL_URL
    [ -z "$XUI_PANEL_URL" ] && echo -e "     ${RED}⚠ Required${NC}"
done
while [ -z "$SUB_BASE_URL" ]; do
    read -p "  🔗 Subscription Base URL (e.g. https://domain.com:2096): " SUB_BASE_URL
    [ -z "$SUB_BASE_URL" ] && echo -e "     ${RED}⚠ Required${NC}"
done

echo ""
echo -e "${YELLOW}Review:${NC}"
echo "  Bot Name:     $BOT_NAME"
echo "  Directory:    $BOT_DIR"
echo "  Owner (👑):   $BOT_OWNER"
echo "  Extra Users:  ${TG_EXTRA_USERS:-none}"
echo "  Bot Token:    ${TG_BOT_TOKEN:0:6}***"
echo "  API Token:    ${XUI_API_TOKEN:0:6}***"
echo "  Panel URL:    $XUI_PANEL_URL"
echo "  Sub Base URL: $SUB_BASE_URL"

echo ""
echo -e "${YELLOW}Review:${NC}"
echo "  Bot Name:     $BOT_NAME"
echo "  Directory:    $BOT_DIR"
echo "  Bot Token:    ${TG_BOT_TOKEN:0:6}***"
echo "  API Token:    ${XUI_API_TOKEN:0:6}***"
echo "  Panel URL:    $XUI_PANEL_URL"
echo "  Allowed IDs:  $TG_ALLOWED_USERS"
echo "  Sub Base URL: $SUB_BASE_URL"
echo ""
read -p "Continue? (y/N): " CONFIRM
[[ "$CONFIRM" =~ ^[Yy]$ ]] || { err "Aborted."; exit 0; }

# ── Install deps ────────────────────────────────────────────
log "Updating system & installing Python..."
apt-get update -qq
apt-get install -y -qq python3 python3-pip python3-venv python3-dev > /dev/null

# ── Create directory ────────────────────────────────────────
log "Creating: $BOT_DIR"
mkdir -p "$BOT_DIR"

# ── Write .env ──────────────────────────────────────────────
log "Writing .env config..."
cat > "$BOT_DIR/.env" << ENVEOF
PANEL_URL=$XUI_PANEL_URL
API_TOKEN=$XUI_API_TOKEN
BOT_OWNER=$BOT_OWNER
ALLOWED_USERS=$TG_ALLOWED_USERS
SUB_BASE_URL=$SUB_BASE_URL
BOT_TOKEN=$TG_BOT_TOKEN
ENVEOF

# ── Write requirements.txt ──────────────────────────────────
cat > "$BOT_DIR/requirements.txt" << 'REQEOF'
python-telegram-bot>=20.0
requests
urllib3
REQEOF

# ── Write bot.py (base64 decoded) ───────────────────────────
log "Writing bot.py..."
BOT_B64=""

echo "$BOT_B64" | base64 -d > "$BOT_DIR/bot.py"

# ── Venv + install ──────────────────────────────────────────
log "Setting up Python venv..."
python3 -m venv "$BOT_DIR/venv"
source "$BOT_DIR/venv/bin/activate"
pip install --upgrade pip -q
pip install -r "$BOT_DIR/requirements.txt" -q

# ── Systemd service ─────────────────────────────────────────
log "Creating systemd service: $SVC_NAME"
cat > "/etc/systemd/system/${SVC_NAME}.service" << UNITEOF
[Unit]
Description=${SVC_NAME} — 3x-UI Telegram Bot
After=network.target

[Service]
User=root
WorkingDirectory=$BOT_DIR
EnvironmentFile=$BOT_DIR/.env
ExecStart=$BOT_DIR/venv/bin/python $BOT_DIR/bot.py
Restart=always
RestartSec=5

[Install]
WantedBy=multi-user.target
UNITEOF

systemctl daemon-reload
systemctl enable "$SVC_NAME"
systemctl start "$SVC_NAME"
sleep 3

# ── Verify ──────────────────────────────────────────────────
if systemctl is-active --quiet "$SVC_NAME"; then
    echo ""
    echo -e "${GREEN}╔════════════════════════════════════════════════════╗${NC}"
    echo -e "${GREEN}║  ✅ Bot installed & running! Arielvpn myanmar      ║${NC}"
    echo -e "${GREEN}╚════════════════════════════════════════════════════╝${NC}"
    echo ""
    info "Name:      $BOT_NAME"
    info "Dir:       $BOT_DIR"
    info "Service:   systemctl status $SVC_NAME"
    info "Logs:      journalctl -u $SVC_NAME -f"
    info "Config:    $BOT_DIR/.env"
    echo ""
    info "Send /start to your bot on Telegram."
    info "Use '👥 Manage Users' button to add more chat IDs anytime."
else
    err "Bot failed to start. Logs:"
    journalctl -u "$SVC_NAME" --no-pager -n 20
fi
